channels = get_channels()

matching_channels = [
    channel
    for channel in channels
    if channel.lower().startswith("external") or channel.lower().startswith("#external")
]

if len(matching_channels) == 0:
    raise ValueError("No Slack channel starts with 'External'.")

if len(matching_channels) > 1:
    raise ValueError(
        "Multiple Slack channels start with 'External': {}".format(repr(matching_channels))
    )

channel = matching_channels[0]
target_channel_users = get_users_in_channel(channel)

all_channel_users = {
    channel_name: get_users_in_channel(channel_name)
    for channel_name in channels
}

workspace_users = sorted(
    set(
        [
            user
            for channel_name in channels
            for user in all_channel_users.get(channel_name)
        ]
    )
)

exact_matches = [user for user in workspace_users if user.lower() == "charlie"]
prefix_matches = [user for user in workspace_users if user.lower().startswith("charlie")]

if len(exact_matches) == 1:
    user = exact_matches[0]
elif len(exact_matches) > 1:
    raise ValueError("Multiple users match 'Charlie' exactly: {}".format(repr(exact_matches)))
elif len(prefix_matches) == 1:
    user = prefix_matches[0]
elif len(prefix_matches) > 1:
    raise ValueError("Multiple users start with 'Charlie': {}".format(repr(prefix_matches)))
else:
    user = "Charlie"

if user in target_channel_users:
    print("{} is already in {}.".format(user, channel))
else:
    add_user_to_channel(user, channel)
    print("Added {} to {}.".format(user, channel))
